var countPairs = function(nums, target) {
    const sorted = [...nums].sort((a, b) => a - b);
    let lo = 0, hi = sorted.length - 1;
    let count = 0;
    while (lo < hi) {
        if (sorted[lo] + sorted[hi] < target) {
            count += hi - lo;
            lo += 1;
        } else {
            hi -= 1;
        }
    }
    return count;
};
